import React from "react";
import { PRIORITY_META, STATUS_META, formatDate } from "../utils/costants";

export default function FeatureCard({ feature, onViewDetails }) {
  const pm = PRIORITY_META[feature.priority];
  const sm = STATUS_META[feature.status];

  return (
    <article 
      className={`card status-${feature.status.replace(" ", "-").toLowerCase()}`}
      onClick={() => onViewDetails && onViewDetails(feature)}
      style={{ cursor: "pointer" }}
    >
      <div className="card-top">
        <span className="priority-badge" style={{ "--badge-color": pm.color }}>
          {feature.priority}
        </span>
        <span className="card-date">{formatDate(feature.createdAt)}</span>
      </div>

      {/* Show image if present */}
      {feature.image && (
        <div style={{ margin: '8px 0', textAlign: 'center' }}>
          <img
            src={`http://localhost:5000/api/features/images/${feature.image}`}
            alt={feature.title}
            style={{ maxWidth: '100%', maxHeight: 180, borderRadius: 8, boxShadow: '0 1px 8px #0001' }}
          />
        </div>
      )}

      {/* Show video player if present */}
      {feature.videoFile && (
        <div style={{ margin: '8px 0', borderRadius: 8, overflow: 'hidden', boxShadow: '0 1px 8px #0001' }}>
          <video
            width="100%"
            height="auto"
            style={{ display: 'block', maxHeight: 200, backgroundColor: '#000' }}
            controls
            onClick={(e) => e.stopPropagation()}
          >
            <source
              src={`http://localhost:5000/api/features/videos/${feature.videoFile}`}
              type="video/mp4"
            />
            Your browser does not support the video tag.
          </video>
        </div>
      )}

      <h3 className="card-title">{feature.title}</h3>
      <p className="card-desc">{feature.description}</p>

      {/* Show video link if present */}
      {feature.videoUrl && (
        <div style={{ margin: '8px 0', padding: '8px 12px', background: 'rgba(124, 106, 247, 0.1)', borderRadius: 8, borderLeft: '3px solid #7c6af7' }}>
          <a 
            href={feature.videoUrl} 
            target="_blank" 
            rel="noopener noreferrer"
            onClick={(e) => e.stopPropagation()}
            style={{ display: 'flex', alignItems: 'center', gap: 6, color: '#7c6af7', textDecoration: 'none', fontWeight: 500, fontSize: 12 }}
          >
            <span>🎥</span>
            <span>Watch Video</span>
            <span style={{ marginLeft: 'auto', fontSize: '10px' }}>↗</span>
          </a>
        </div>
      )}

      <div className="card-footer">
        <span
          className={`status-btn status-${feature.status.replace(" ", "-").toLowerCase()}`}
          title={sm.label}
        >
          <span className="status-icon">{sm.icon}</span>
          {sm.label}
        </span>
      </div>
    </article>
  );
}
